def {{nama_fungsi}}():
    """Return list dict pid/name. Best-effort cross-platform."""
    import subprocess, sys
    procs = []
    try:
        if sys.platform.startswith('win'):
            out = subprocess.check_output(['tasklist', '/FO', 'CSV', '/NH'], text=True, stderr=subprocess.DEVNULL)
            for line in out.splitlines():
                parts = [p.strip('"') for p in line.split('","')]
                if parts:
                    procs.append({'name': parts[0], 'pid': parts[1] if len(parts) > 1 else ''})
        else:
            out = subprocess.check_output(['ps', '-eo', 'pid,comm'], text=True, stderr=subprocess.DEVNULL)
            for line in out.splitlines()[1:]:
                parts = line.strip().split(None, 1)
                if len(parts) == 2:
                    procs.append({'pid': parts[0], 'name': parts[1]})
    except Exception:
        pass
    return procs

def {{nama_fungsi}}(keys, required=False, defaults=None):
    """keys: list nama env. Return dict."""
    import os
    defaults = defaults or {}
    result = {}
    missing = []
    for k in keys:
        v = os.environ.get(k, defaults.get(k))
        if v is None and required:
            missing.append(k)
        result[k] = v
    if missing:
        raise EnvironmentError(f"Missing required env vars: {', '.join(missing)}")
    return result

def {{nama_fungsi}}(func=None, signals=None):
    """Decorator: graceful shutdown on signals."""
    import signal, functools
    if signals is None:
        signals = [signal.SIGINT, signal.SIGTERM]
    def decorator(f):
        @functools.wraps(f)
        def wrapper(*args, **kwargs):
            stop = {'flag': False}
            def handler(signum, frame):
                stop['flag'] = True
            old = {}
            for s in signals:
                try:
                    old[s] = signal.signal(s, handler)
                except Exception:
                    pass
            try:
                return f(*args, stop_flag=lambda: stop['flag'], **kwargs)
            finally:
                for s, h in old.items():
                    try:
                        signal.signal(s, h)
                    except Exception:
                        pass
        return wrapper
    if func is None:
        return decorator
    return decorator(func)

class {{nama_class}}:
    """PID file helper."""
    def __init__(self, path):
        self.path = path

    def write(self):
        import os
        with open(self.path, 'w') as f:
            f.write(str(os.getpid()))

    def read(self):
        try:
            with open(self.path) as f:
                return int(f.read().strip())
        except Exception:
            return None

    def remove(self):
        import os
        try:
            os.remove(self.path)
        except OSError:
            pass

    def is_running(self):
        pid = self.read()
        if not pid:
            return False
        import os
        try:
            os.kill(pid, 0)
            return True
        except OSError:
            return False

